<?php
namespace App\Http\Controllers; use Illuminate\Http\Request; use Illuminate\Support\Facades\Auth;
class AuthController extends Controller {public function create(){return view('auth.login');}public function store(Request $r){$data=$r->validate(['email'=>['required','email'],'password'=>['required','string']]);if(!Auth::attempt($data,$r->boolean('remember'))){return back()->withErrors(['email'=>'อีเมลหรือรหัสผ่านไม่ถูกต้อง'])->onlyInput('email');}$r->session()->regenerate();return redirect()->intended(route('admin.dashboard'));}public function destroy(Request $r){Auth::logout();$r->session()->invalidate();$r->session()->regenerateToken();return redirect()->route('home');}}
